INSERT INTO `v1_372d63fbd9521d18ff3822bb100fe1cd5cd49a1098718bdd6ad5cbdbedffc78c` VALUES ("ツムギのボトルキャップ", 0.75, 6, 11601, "ツムギ・オンステージ！ツムギがキャップのステージでかわいく\nポーズを決めている。どこでも好きな場所に気軽に飾ることが可\n能。", 1, 0.625);
